namespace Database\Seeders\Data;

/**
 * Temporary developer notes describing the intended puzzles.
 * Remove this file and UI references when real puzzles are implemented.
 */
class TwelveBarrelsPuzzleNotes
{
    /**
     * @return array<int, string>
     */
    public static function all(): array
    {
        return [
            1 => "فرم: معمای AR نقشهٔ نیمه‌شفاف Setterberg روی دوربین.\nفعال‌سازی: اسکن یادمان Setterberg + ایستادن روبه‌روی کلیسا (GPS).\nپیاده‌سازی: نقشه با زاویهٔ اشتباه باز می‌شود؛ بازیکن شمال را با قطب‌نمای اپ هماهنگ می‌کند، پلان صلیبی کلیسا و محور خیابان را روی بافت واقعی منطبق می‌کند؛ مسیر سیاه گاری ظاهر می‌شود.\nپاسخ: ضربه روی مقصد + انتخاب «زندان» از ۴ گزینه → کد VANKILA.",

            2 => "فرم: UI خط‌زمان + دسته‌بندی گزاره‌ها (نه AR داخل زندان).\nفعال‌سازی: اسکن دروازه/دیوار بیرونی.\nدارایی: ۴ کارت زمانی + ۱ کارت همدستی بیرونی.\nپیاده‌سازی: چینش کارت‌ها روی تایم‌لاین؛ سه گزاره در ستون‌های قطعی / ممکن / ناممکن. راه‌حل: حضور دو آنتی = ناممکن؛ دریافت ۴ بشکه = قطعی؛ همدستی بیرونی = ممکن. سپس حرکت گوشی مثل چراغ روی دفتر دیجیتال → ظهور VALO KIRJOITTAA → کد VALO.",

            3 => "فرم: ویرایشگر نگاتیو شیشه‌ای (بازسازی داستانی).\nفعال‌سازی: اسکن صلیب سرخ/ویترین؛ AR قاب عکاسی روی نما.\nدارایی: ۲ نگاتیو (گاری + انعکاس).\nپیاده‌سازی: برگرداندن افقی نگاتیو دوم، انطباق ۴ علامت گوشه، تنظیم نور/کنتراست؛ ضربه روی ۳ جزئیات: چرخ تمیز، حروف H.S.، عدد رومی III. اپ نام H. Sjöberg را از فهرست تاجران نشان می‌دهد → کد SJÖBERG. سرنخ: انبار فرعی III.",

            4 => "فرم: قفسهٔ مجازی فروشگاه + ترتیب خرید از رسید.\nفعال‌سازی: اسکن نمای تاریخی/نشانگر خیابان.\nدارایی: ۶ کالای مجازی (برزنت، گچ، طناب، موم مهر، روغن چراغ، پارچه) هر کدام با یک حرف روی قفسه.\nپیاده‌سازی: مقایسهٔ رسید پاره‌شده با تصویر Julia؛ انتخاب کالاها به ترتیب رسید (نه چپ‌به‌راست قفسه‌ها) → حروف KIRKKO. روی رسید حوالهٔ J.K. شمارهٔ ۳۱۸ دیده می‌شود → کد KIRKKO.",

            5 => "فرم: پازل سه‌تکهٔ رسید شفاف مبتنی بر موقعیت.\nفعال‌سازی: سه نقطهٔ GPS امن روی نما؛ در هر نقطه گوشی رو به یکی از قوس‌ها.\nپیاده‌سازی: نقطه ۱ = بالای رسید، نقطه ۲ = مهر و عدد، نقطه ۳ = امضا و پشت‌رسید؛ چیدن قطعات مثل پازل. رسید تحویل ۶ بشکه را تأیید می‌کند؛ پشت آن «ستون چهارم دفتر تالار شهر» + واژهٔ RÅDHUS → کد RÅDHUS.",

            6 => "فرم: میز حسابداری AR + مقایسهٔ اسناد/مهر.\nفعال‌سازی: اسکن نمای تالار شهر قدیم (VÖS).\nدارایی: جدول تخصیص ۳۰ بشکه + مهرهای معتبر/جعلی + دو timestamp.\nپیاده‌سازی: محاسبهٔ ۳۰−۴−۶−۸=۱۲؛ مقایسهٔ بریدگی مهر (ساعت ۲ معتبر در برابر ساعت ۱۰ آینه‌ای جعلی)؛ شمارهٔ رسید تکراری؛ موجودی صفر؛ اختلاف ۱۰ ساعتهٔ خبر ناشناس با شمارش رسمی. نتیجه: ۱۲ بشکه گم‌شده + خبر پیش از کشف → کد ENNEN.",

            7 => "فرم: روزنامهٔ دیجیتال + شابلون حروف‌چینی نیمه‌شفاف (frisket).\nفعال‌سازی: اسکن نمای دفتر/ویترین.\nپیاده‌سازی: حرکت شابلون روی صفحه، انطباق ۴ علامت گوشهٔ چاپ؛ حروف مخفی از ستون‌های مختلف → KJELLMAN. پشت شابلون تاریخ/ساعت دست‌نویس ۱۸ نوامبر ساعت ۲۲ (قبل از شمارش صبح). کد KJELLMAN → مهمان‌خانهٔ Kjellman.",

            8 => "فرم: صحنهٔ AR تالار عروسی + ۴ کارت حضور + شهادت صوتی/متنی.\nفعال‌سازی: اسکن در ورودی.\nدارایی: کارت‌های Kurtén / Wasastjerna / Levón / V.E.G. + شهادت نوازنده دربارهٔ گاری حیاط پشتی حدود ساعت ۸.\nپیاده‌سازی: انتخاب فردی که در بازهٔ ۱۹:۵۵–۲۰:۱۵ غایب است، کلید حیاط پشتی دارد، و با عدد ۱۲ و حوالهٔ J.K. مرتبط است → V.E.G.؛ سپس حواله بازیکن را به Kurtén می‌فرستد → کد KURTÉN. هویت کامل هنوز باز نمی‌شود.",

            9 => "فرم: بازرسی سه‌حواله با «نور آسمان» (sensor / نمای روشن).\nفعال‌سازی: اسکن نشانهٔ بیرونی؛ سه حوالهٔ ۳۱۶ / ۳۱۷ (معتبر) و ۳۱۸ (مشکوک).\nپیاده‌سازی: گوشی رو به نور → علامت آب؛ تاج یکسان روی معتبرها، وارونه + الیاف متفاوت روی ۳۱۸؛ امضای جعلی کمی بالاتر از خط. انتخاب ۳۱۸ به‌عنوان جعل؛ پشت سند: ۱۴۴ lp پنبهٔ ضایعاتی / ضمیمهٔ III / فرم A.A.L. → کد 144. Kurtén تبرئه می‌شود.",

            10 => "فرم: تختهٔ سیاه AR با دو چرخ گردان واحد تبدیل.\nفعال‌سازی: اسکن نشانگر مدرسه (درگاه بازسازی؛ ادعای ساختمان تاریخی لازم نیست).\nبازیکن می‌داند محموله چاودار، ۱۲ بشکه مفقود، سند کارخانه ۱۴۴ لیویسکا است. سه گزینه: گندم ۱۱×۱۳، چاودار ۱۲×۱۲، جو ۱۴×۱۰.\nپیاده‌سازی: تنظیم چرخ‌ها روی «۱۲ بشکه» + «چاودار» → ۱۴۴ و انطباق برگهٔ کارخانه. پیام هدایت به محفل تاجران → کد SALONKI.",

            11 => "فرم: میز AR + ۴ پرتره + سیستم پرسش/گفت‌وگوی شاخه‌ای + جدول استنتاج.\nفعال‌سازی: اسکن نما/ویترین Bacchus–Svenska Klubben (محفل داستانی ۱۸۶۷).\nپیاده‌سازی: ۶ پرسش از ۸؛ پر کردن ماتریس دسترسی / فرصت / آگاهی از عدد ۱۲ / ارتباط با انبار III. کلید: لغزش زبانی Granholm که «دوازده بشکه» می‌گوید بدون آنکه بازیکن گفته باشد. پاسخ مجرم منطقی: Viktor Granholm؛ هنگام خروج موم Wasastjerna می‌افتد (سرنخ گمراه‌کننده) → کد WASASTJERNA.",

            12 => "فرم: جمع‌آوری دوقطعه‌ای نامه/مهر از دو زاویهٔ GPS.\nفعال‌سازی: دو نقطهٔ امن روی نمای Wasastjernan palatsi.\nپیاده‌سازی: نقطه ۱ = نیمهٔ چپ مهر + ابتدای نامه، نقطه ۲ = نیمهٔ راست + انتهای نامه؛ چرخش و انطباق دو تصویر. نامهٔ رد پیشنهاد احتکار از Wasastjerna به Granholm؛ درخواست بازگرداندن نقش مهر. نوشتهٔ گوشه: آمار گمرک → کد TILASTO. Wasastjerna تبرئه می‌شود.",

            13 => "فرم: جدول آماری دیجیتال (برش آمار واقعی) + محاسبه + انتخاب استنتاج.\nفعال‌سازی: اسکن نشان کتابخانه / NFC + geofence.\nپیاده‌سازی: یافتن ردیف Nikolainkaupunki؛ خواندن ستون ۱۸۶۷ = 435,923؛ اختلاف با ۱۸۶۶: 109,511؛ انتخاب نتیجهٔ «انحراف محلی پس از ورود، نه نبود قحطی/توزیع کامل». سپس مانیفست گمرک سی‌بشکه‌ای + کارت تدفین Alma Ungren → کد ALMA.",

            14 => "فرم: معمای صوتی/متنی (هدفون اجباری؛ بدون لمس قبر).\nفعال‌سازی: geofence مسیر نزدیک قبر + تشخیص شکل کلی صلیب (بدون پلاک روی قبر)؛ دسترس‌پذیری از ورودی گورستان.\nدارایی: ملودی اصل + متن صحیح روی صفحه در برابر صوت با دو واژهٔ جابه‌جا (villa / puu).\nپیاده‌سازی: انتخاب دو واژهٔ جابه‌جا، چیدن درست، چسباندن بدون فاصله → PUU + VILLA = PUUVILLA (پنبه). کد PUUVILLA → Fabriikki.",

            15 => "فرم: نقشهٔ مجازی انبار + ۴ قفل پایانی + صحنهٔ AR انبار.\nفعال‌سازی: اسکن ورودی آجری / محل بارگیری.\nقفل ۱: انتخاب انبار III از سرنخ Julia.\nقفل ۲: «هر دو توصیف یک بارند» (۱۴۴ لیویسکا پنبهٔ ضایعاتی = ۱۲ بشکه چاودار).\nقفل ۳: انتخاب ۳ سند جعلی (حوالهٔ ۳۱۸، رسید ذخیره، فرم حمل کارخانه).\nقفل ۴: انتخاب Viktor Granholm.\nجملهٔ نهایی به پرسش «غله چه شد؟» → EI VARASTETTU. KÄTKETTY.\nسپس AR: ۱۲ بشکه پشت پنبه + جعبهٔ شواهد + انتخاب اخلاقی سه‌گانه (قانون / نجات / افشا).",
        ];
    }

    public static function forStage(int $order): ?string
    {
        return self::all()[$order] ?? null;
    }
}
